module top_module(clk, reset, load, data_in, data_out);input clk, reset, load;
    input [15:0] data_in;
    output [15:0] data_out;

    reg [15:0] reg_data;

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or negedge reset or posedge dbg_halt) begin
        if (!reset) begin
            reg_data <= 16'h0;
        end else if (load) begin
            reg_data <= data_in;
        end
    end

    assign data_out = reg_data;

endmodule
